#!/usr/bin/env python3
from pathlib import Path
import json

ROOT = Path.cwd()
FILES = {'docs/notification-event-wiring.md': '# Betsy Home notification event wiring\n\nThis patch connects the local-safe notification service to marketplace events through reusable event helpers and API endpoints.\n\n## What it adds\n\n- `src/lib/notification-events.ts`\n- `/api/notifications/events/order-created`\n- `/api/notifications/events/shipping-updated`\n- `/api/notifications/events/refund-requested`\n- `/api/notifications/events/refund-resolved`\n- `/api/notifications/events/manual-refund-followup`\n- `/admin/notification-events`\n\n## Local behavior\n\nNotifications are still logged only. They are written to:\n\n```text\n.local-notifications/notifications.jsonl\n```\n\n## How to use from existing server actions\n\nAfter an order is created:\n\n```ts\nimport { notifyOrderCreated } from "@/lib/notification-events";\n\nawait notifyOrderCreated(order.id);\n```\n\nAfter shipping is updated:\n\n```ts\nimport { notifyShippingUpdated } from "@/lib/notification-events";\n\nawait notifyShippingUpdated(order.id);\n```\n\nAfter a refund request is submitted:\n\n```ts\nimport { notifyRefundRequested } from "@/lib/notification-events";\n\nawait notifyRefundRequested(order.id);\n```\n\nAfter seller approves/rejects a refund:\n\n```ts\nimport { notifyRefundResolved } from "@/lib/notification-events";\n\nawait notifyRefundResolved(order.id);\n```\n\nAfter admin manual refund follow-up is needed:\n\n```ts\nimport { notifyManualRefundFollowup } from "@/lib/notification-events";\n\nawait notifyManualRefundFollowup(order.id);\n```\n\n## API endpoint testing\n\nPOST JSON:\n\n```json\n{"orderId":"YOUR_ORDER_ID"}\n```\n\nto:\n\n```text\n/api/notifications/events/order-created\n/api/notifications/events/shipping-updated\n/api/notifications/events/refund-requested\n/api/notifications/events/refund-resolved\n/api/notifications/events/manual-refund-followup\n```\n', 'src/lib/notification-events.ts': 'import { prisma } from "@/lib/prisma";\nimport {\n  sendAdminManualRefundFollowup,\n  sendNotification,\n  sendRefundApproved,\n  sendRefundRejected,\n  sendRefundRequestSubmitted,\n  sendSellerNewOrderAlert,\n  sendShippingUpdate,\n} from "@/lib/notification-service";\n\nfunction money(value: unknown) {\n  const amount =\n    typeof (value as any)?.toNumber === "function"\n      ? (value as any).toNumber()\n      : Number(value ?? 0);\n\n  return new Intl.NumberFormat("en-US", {\n    style: "currency",\n    currency: "USD",\n  }).format(Number.isFinite(amount) ? amount : 0);\n}\n\nfunction getBaseUrl() {\n  return (\n    process.env.NEXT_PUBLIC_APP_URL ??\n    process.env.NEXTAUTH_URL ??\n    "http://localhost:3000"\n  ).replace(/\\/$/, "");\n}\n\nfunction firstDefined<T>(...values: T[]) {\n  return values.find((value) => value !== undefined && value !== null);\n}\n\nfunction getOrderNumber(order: any) {\n  return firstDefined(order?.orderNumber, order?.number, order?.code, order?.id) as string;\n}\n\nfunction getOrderTotal(order: any) {\n  return firstDefined(order?.total, order?.totalAmount, order?.amount, 0);\n}\n\nfunction getCustomerEmail(order: any) {\n  return firstDefined(\n    order?.customer?.email,\n    order?.user?.email,\n    order?.buyer?.email,\n    order?.customerEmail,\n    order?.email\n  ) as string | undefined;\n}\n\nfunction getSellerEmail(order: any) {\n  return firstDefined(\n    order?.shop?.owner?.email,\n    order?.shop?.seller?.email,\n    order?.seller?.email,\n    order?.shop?.sellerEmail\n  ) as string | undefined;\n}\n\nfunction getShopName(order: any) {\n  return firstDefined(order?.shop?.shopName, order?.shop?.name, "Betsy Home") as string;\n}\n\nfunction getProductTitle(order: any) {\n  const firstItem = order?.items?.[0];\n  return firstDefined(\n    firstItem?.product?.title,\n    firstItem?.product?.name,\n    firstItem?.productTitle,\n    firstItem?.title,\n    "your item"\n  ) as string;\n}\n\nasync function loadOrder(orderId: string) {\n  const db = prisma as any;\n\n  const include: any = {\n    items: {\n      include: {\n        product: true,\n      },\n    },\n    shop: {\n      include: {\n        owner: true,\n        seller: true,\n      },\n    },\n    customer: true,\n    user: true,\n    buyer: true,\n  };\n\n  try {\n    return await db.order.findUnique({\n      where: { id: orderId },\n      include,\n    });\n  } catch {\n    // Some schemas will not have every relation above. Fall back to lighter queries.\n  }\n\n  try {\n    return await db.order.findUnique({\n      where: { id: orderId },\n      include: {\n        items: true,\n        shop: true,\n      },\n    });\n  } catch {\n    return await db.order.findUnique({\n      where: { id: orderId },\n    });\n  }\n}\n\nfunction orderPayload(order: any) {\n  const orderNumber = getOrderNumber(order);\n  const baseUrl = getBaseUrl();\n\n  return {\n    orderNumber,\n    orderTotal: money(getOrderTotal(order)),\n    shopName: getShopName(order),\n    customerEmail: getCustomerEmail(order),\n    sellerEmail: getSellerEmail(order),\n    productTitle: getProductTitle(order),\n    trackingCarrier: firstDefined(order?.trackingCarrier, order?.carrier, "") as string,\n    trackingNumber: firstDefined(order?.trackingNumber, "") as string,\n    trackingUrl: firstDefined(order?.trackingUrl, "") as string,\n    refundReason: firstDefined(order?.refundReason, "") as string,\n    resolutionNote: firstDefined(\n      order?.refundResolutionNote,\n      order?.resolutionNote,\n      ""\n    ) as string,\n    adminReference: firstDefined(\n      order?.stripeRefundId,\n      order?.manualRefundReference,\n      ""\n    ) as string,\n    actionUrl: `${baseUrl}/account/orders/${order?.id}`,\n  };\n}\n\nasync function adminEmail() {\n  return (\n    process.env.ADMIN_EMAIL ??\n    process.env.SUPPORT_EMAIL ??\n    "admin@betsyhome.test"\n  );\n}\n\nexport async function notifyOrderCreated(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = orderPayload(order);\n  const results = [];\n\n  if (payload.customerEmail) {\n    results.push(\n      await sendNotification({\n        kind: "order_confirmation",\n        to: payload.customerEmail,\n        payload,\n      })\n    );\n  }\n\n  if (payload.sellerEmail) {\n    results.push(await sendSellerNewOrderAlert(payload.sellerEmail, payload));\n  }\n\n  return {\n    ok: true,\n    event: "order_created",\n    orderId,\n    notifications: results.length,\n    results,\n  };\n}\n\nexport async function notifyShippingUpdated(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = orderPayload(order);\n  const to = payload.customerEmail;\n\n  if (!to) {\n    return { ok: false, reason: "customer_email_not_found", orderId };\n  }\n\n  const result = await sendShippingUpdate(to, payload);\n\n  return {\n    ok: true,\n    event: "shipping_updated",\n    orderId,\n    notifications: 1,\n    result,\n  };\n}\n\nexport async function notifyRefundRequested(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = orderPayload(order);\n  const results = [];\n\n  if (payload.sellerEmail) {\n    results.push(await sendRefundRequestSubmitted(payload.sellerEmail, payload));\n  }\n\n  results.push(\n    await sendRefundRequestSubmitted(await adminEmail(), {\n      ...payload,\n      actionUrl: `${getBaseUrl()}/admin/refunds`,\n    })\n  );\n\n  return {\n    ok: true,\n    event: "refund_requested",\n    orderId,\n    notifications: results.length,\n    results,\n  };\n}\n\nexport async function notifyRefundResolved(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = orderPayload(order);\n  const to = payload.customerEmail;\n\n  if (!to) {\n    return { ok: false, reason: "customer_email_not_found", orderId };\n  }\n\n  const status = String(\n    firstDefined(order?.refundRequestStatus, order?.refundStatus, "")\n  ).toUpperCase();\n\n  const result =\n    status === "REJECTED" || status === "DECLINED"\n      ? await sendRefundRejected(to, payload)\n      : await sendRefundApproved(to, payload);\n\n  return {\n    ok: true,\n    event: "refund_resolved",\n    orderId,\n    notifications: 1,\n    result,\n  };\n}\n\nexport async function notifyManualRefundFollowup(orderId: string) {\n  const order = await loadOrder(orderId);\n\n  if (!order) {\n    return { ok: false, reason: "order_not_found", orderId };\n  }\n\n  const payload = {\n    ...orderPayload(order),\n    actionUrl: `${getBaseUrl()}/admin/refunds`,\n  };\n\n  const result = await sendAdminManualRefundFollowup(await adminEmail(), payload);\n\n  return {\n    ok: true,\n    event: "manual_refund_followup",\n    orderId,\n    notifications: 1,\n    result,\n  };\n}\n\nexport const notificationEventHandlers = {\n  order_created: notifyOrderCreated,\n  shipping_updated: notifyShippingUpdated,\n  refund_requested: notifyRefundRequested,\n  refund_resolved: notifyRefundResolved,\n  manual_refund_followup: notifyManualRefundFollowup,\n};\n', 'src/app/api/notifications/events/order-created/route.ts': 'import { NextResponse } from "next/server";\nimport { notifyOrderCreated } from "@/lib/notification-events";\n\nexport const dynamic = "force-dynamic";\n\nexport async function POST(request: Request) {\n  try {\n    const body = await request.json();\n    const orderId = body?.orderId;\n\n    if (!orderId) {\n      return NextResponse.json(\n        { ok: false, error: "orderId is required" },\n        { status: 400 }\n      );\n    }\n\n    const result = await notifyOrderCreated(orderId);\n    return NextResponse.json(result, { status: result.ok ? 200 : 404 });\n  } catch (error) {\n    return NextResponse.json(\n      {\n        ok: false,\n        error: error instanceof Error ? error.message : String(error),\n      },\n      { status: 500 }\n    );\n  }\n}\n', 'src/app/api/notifications/events/shipping-updated/route.ts': 'import { NextResponse } from "next/server";\nimport { notifyShippingUpdated } from "@/lib/notification-events";\n\nexport const dynamic = "force-dynamic";\n\nexport async function POST(request: Request) {\n  try {\n    const body = await request.json();\n    const orderId = body?.orderId;\n\n    if (!orderId) {\n      return NextResponse.json(\n        { ok: false, error: "orderId is required" },\n        { status: 400 }\n      );\n    }\n\n    const result = await notifyShippingUpdated(orderId);\n    return NextResponse.json(result, { status: result.ok ? 200 : 404 });\n  } catch (error) {\n    return NextResponse.json(\n      {\n        ok: false,\n        error: error instanceof Error ? error.message : String(error),\n      },\n      { status: 500 }\n    );\n  }\n}\n', 'src/app/api/notifications/events/refund-requested/route.ts': 'import { NextResponse } from "next/server";\nimport { notifyRefundRequested } from "@/lib/notification-events";\n\nexport const dynamic = "force-dynamic";\n\nexport async function POST(request: Request) {\n  try {\n    const body = await request.json();\n    const orderId = body?.orderId;\n\n    if (!orderId) {\n      return NextResponse.json(\n        { ok: false, error: "orderId is required" },\n        { status: 400 }\n      );\n    }\n\n    const result = await notifyRefundRequested(orderId);\n    return NextResponse.json(result, { status: result.ok ? 200 : 404 });\n  } catch (error) {\n    return NextResponse.json(\n      {\n        ok: false,\n        error: error instanceof Error ? error.message : String(error),\n      },\n      { status: 500 }\n    );\n  }\n}\n', 'src/app/api/notifications/events/refund-resolved/route.ts': 'import { NextResponse } from "next/server";\nimport { notifyRefundResolved } from "@/lib/notification-events";\n\nexport const dynamic = "force-dynamic";\n\nexport async function POST(request: Request) {\n  try {\n    const body = await request.json();\n    const orderId = body?.orderId;\n\n    if (!orderId) {\n      return NextResponse.json(\n        { ok: false, error: "orderId is required" },\n        { status: 400 }\n      );\n    }\n\n    const result = await notifyRefundResolved(orderId);\n    return NextResponse.json(result, { status: result.ok ? 200 : 404 });\n  } catch (error) {\n    return NextResponse.json(\n      {\n        ok: false,\n        error: error instanceof Error ? error.message : String(error),\n      },\n      { status: 500 }\n    );\n  }\n}\n', 'src/app/api/notifications/events/manual-refund-followup/route.ts': 'import { NextResponse } from "next/server";\nimport { notifyManualRefundFollowup } from "@/lib/notification-events";\n\nexport const dynamic = "force-dynamic";\n\nexport async function POST(request: Request) {\n  try {\n    const body = await request.json();\n    const orderId = body?.orderId;\n\n    if (!orderId) {\n      return NextResponse.json(\n        { ok: false, error: "orderId is required" },\n        { status: 400 }\n      );\n    }\n\n    const result = await notifyManualRefundFollowup(orderId);\n    return NextResponse.json(result, { status: result.ok ? 200 : 404 });\n  } catch (error) {\n    return NextResponse.json(\n      {\n        ok: false,\n        error: error instanceof Error ? error.message : String(error),\n      },\n      { status: 500 }\n    );\n  }\n}\n', 'src/app/(admin)/admin/notification-events/page.tsx': 'export const dynamic = "force-dynamic";\n\nconst events = [\n  {\n    name: "Order created",\n    path: "/api/notifications/events/order-created",\n    sends: "Customer order confirmation + seller new order alert",\n  },\n  {\n    name: "Shipping updated",\n    path: "/api/notifications/events/shipping-updated",\n    sends: "Customer shipping update",\n  },\n  {\n    name: "Refund requested",\n    path: "/api/notifications/events/refund-requested",\n    sends: "Seller refund request alert + admin copy",\n  },\n  {\n    name: "Refund resolved",\n    path: "/api/notifications/events/refund-resolved",\n    sends: "Customer refund approved/rejected email",\n  },\n  {\n    name: "Manual refund follow-up",\n    path: "/api/notifications/events/manual-refund-followup",\n    sends: "Admin manual refund follow-up alert",\n  },\n];\n\nexport default function AdminNotificationEventsPage() {\n  return (\n    <main className="mx-auto max-w-6xl px-6 py-12">\n      <div>\n        <p className="text-sm font-bold uppercase tracking-[0.35em] text-clay">\n          Admin\n        </p>\n        <h1 className="mt-4 text-4xl font-black text-charcoal">\n          Notification event wiring\n        </h1>\n        <p className="mt-2 max-w-3xl text-charcoal/70">\n          These endpoints connect real order, shipping, refund, and manual follow-up\n          events to the local-safe notification system.\n        </p>\n      </div>\n\n      <section className="mt-8 rounded-3xl border border-clay/20 bg-white p-6">\n        <h2 className="text-2xl font-black text-charcoal">Event endpoints</h2>\n\n        <div className="mt-5 space-y-3">\n          {events.map((event) => (\n            <div\n              key={event.path}\n              className="rounded-2xl border border-clay/10 bg-cream p-4"\n            >\n              <p className="font-black text-charcoal">{event.name}</p>\n              <p className="mt-1 text-sm text-charcoal/70">{event.sends}</p>\n              <code className="mt-3 block break-all rounded-xl bg-white p-3 text-xs text-charcoal/70">\n                POST {event.path} {"{ orderId: \\"...your-order-id...\\" }"}\n              </code>\n            </div>\n          ))}\n        </div>\n      </section>\n\n      <section className="mt-6 rounded-3xl border border-clay/20 bg-cream p-6">\n        <h2 className="text-xl font-black text-charcoal">Integration note</h2>\n        <p className="mt-2 text-charcoal/70">\n          Existing checkout, seller shipping, and refund server actions can call the\n          helpers in <code>src/lib/notification-events.ts</code>. Notifications remain\n          log-only until a real provider is enabled.\n        </p>\n      </section>\n    </main>\n  );\n}\n', 'scripts/test-notification-event.cjs': 'const eventName = process.argv[2];\nconst orderId = process.argv[3];\n\nconst paths = {\n  order_created: "/api/notifications/events/order-created",\n  shipping_updated: "/api/notifications/events/shipping-updated",\n  refund_requested: "/api/notifications/events/refund-requested",\n  refund_resolved: "/api/notifications/events/refund-resolved",\n  manual_refund_followup: "/api/notifications/events/manual-refund-followup",\n};\n\nif (!eventName || !orderId || !paths[eventName]) {\n  console.log("Usage:");\n  console.log("  node scripts/test-notification-event.cjs order_created ORDER_ID");\n  console.log("Events:");\n  Object.keys(paths).forEach((key) => console.log(`  ${key}`));\n  process.exit(1);\n}\n\nfetch(`http://localhost:3000${paths[eventName]}`, {\n  method: "POST",\n  headers: { "Content-Type": "application/json" },\n  body: JSON.stringify({ orderId }),\n})\n  .then(async (response) => {\n    const text = await response.text();\n    console.log(response.status, text);\n    if (!response.ok) process.exitCode = 1;\n  })\n  .catch((error) => {\n    console.error(error);\n    process.exitCode = 1;\n  });\n'}

def ensure_parent(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)

def write_file(path_str: str, content: str):
    path = ROOT / path_str
    ensure_parent(path)
    path.write_text(content, encoding="utf-8")
    print(f"wrote {path_str}")

for path_str, content in FILES.items():
    write_file(path_str, content)

pkg_path = ROOT / "package.json"
if pkg_path.exists():
    try:
        pkg = json.loads(pkg_path.read_text(encoding="utf-8"))
        scripts = pkg.setdefault("scripts", {})
        scripts.setdefault("notifications:event", "node scripts/test-notification-event.cjs")
        pkg_path.write_text(json.dumps(pkg, indent=2) + "\n", encoding="utf-8")
        print("updated package.json with notifications:event script")
    except Exception as error:
        print("package.json update skipped:", error)

print("\nDone.")
print("Next:")
print("  rm -rf .next")
print("  npx prisma generate")
print("  npm run dev")
print("Then open:")
print("  http://localhost:3000/admin/notification-events")
